"""
FILE: auth_html.py  (Client Module)
Three constants: AUTH_CSS, AUTH_BODY, AUTH_JS — imported by AuthForm.py
"""

AUTH_CSS  = ':root {\n    --bg: #0d0f14;\n    --surface: #13161d;\n    --surface-2: #1a1e28;\n    --border: #252a38;\n    --accent: #e8ff47;\n    --accent-dim: rgba(232,255,71,0.12);\n    --accent-glow: rgba(232,255,71,0.3);\n    --text: #f0f2f8;\n    --text-muted: #6b7394;\n    --text-mid: #9da3bf;\n    --green: #3dffa0;\n    --green-dim: rgba(61,255,160,0.1);\n    --red: #ff4d6d;\n    --red-dim: rgba(255,77,109,0.12);\n    --radius: 20px;\n    --radius-sm: 12px;\n  }\n  * { box-sizing: border-box; margin: 0; padding: 0; }\n\n  .auth-root {\n    min-height: 100vh;\n    background: var(--bg);\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    font-family: \'DM Sans\', sans-serif;\n    position: relative;\n    overflow: hidden;\n  }\n\n  /* animated grid background */\n  .auth-root::before {\n    content: \'\';\n    position: fixed; inset: 0;\n    background-image:\n      linear-gradient(rgba(232,255,71,0.04) 1px, transparent 1px),\n      linear-gradient(90deg, rgba(232,255,71,0.04) 1px, transparent 1px);\n    background-size: 48px 48px;\n    pointer-events: none;\n  }\n\n  /* glow blob */\n  .auth-root::after {\n    content: \'\';\n    position: fixed;\n    width: 600px; height: 600px;\n    background: radial-gradient(circle, rgba(232,255,71,0.06) 0%, transparent 70%);\n    top: -100px; left: -100px;\n    pointer-events: none;\n  }\n\n  /* ── SPLIT LAYOUT ── */\n  .auth-split {\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    width: 100%;\n    max-width: 1000px;\n    min-height: 580px;\n    background: var(--surface);\n    border: 1px solid var(--border);\n    border-radius: var(--radius);\n    overflow: hidden;\n    position: relative;\n    z-index: 1;\n    box-shadow: 0 40px 80px rgba(0,0,0,0.5);\n    animation: authIn 0.5s cubic-bezier(0.22,1,0.36,1) both;\n  }\n\n  @keyframes authIn {\n    from { opacity: 0; transform: translateY(30px) scale(0.97); }\n    to   { opacity: 1; transform: translateY(0) scale(1); }\n  }\n\n  /* ── LEFT PANEL (branding) ── */\n  .auth-brand {\n    background: linear-gradient(145deg, #111419 0%, #0d0f14 100%);\n    padding: 48px;\n    display: flex;\n    flex-direction: column;\n    justify-content: space-between;\n    border-right: 1px solid var(--border);\n    position: relative;\n    overflow: hidden;\n  }\n\n  .auth-brand::before {\n    content: \'⚙\';\n    position: absolute;\n    font-size: 320px;\n    line-height: 1;\n    bottom: -60px;\n    right: -60px;\n    opacity: 0.03;\n    pointer-events: none;\n  }\n\n  .brand-logo {\n    display: flex;\n    align-items: center;\n    gap: 12px;\n    font-family: \'Syne\', sans-serif;\n    font-weight: 800;\n    font-size: 20px;\n    color: var(--text);\n  }\n\n  .brand-logo-mark {\n    width: 40px; height: 40px;\n    background: var(--accent);\n    border-radius: 10px;\n    display: flex; align-items: center; justify-content: center;\n    font-size: 18px; color: #000;\n    flex-shrink: 0;\n  }\n\n  .brand-tagline {\n    font-family: \'Syne\', sans-serif;\n    font-weight: 800;\n    font-size: clamp(28px, 3vw, 38px);\n    line-height: 1.15;\n    letter-spacing: -1px;\n    color: var(--text);\n    margin-bottom: 16px;\n  }\n\n  .brand-tagline span { color: var(--accent); }\n\n  .brand-desc {\n    font-size: 14px;\n    color: var(--text-muted);\n    line-height: 1.6;\n    margin-bottom: 32px;\n  }\n\n  .brand-features {\n    display: flex;\n    flex-direction: column;\n    gap: 12px;\n  }\n\n  .brand-feature {\n    display: flex;\n    align-items: center;\n    gap: 10px;\n    font-size: 13px;\n    color: var(--text-mid);\n  }\n\n  .brand-feature-dot {\n    width: 6px; height: 6px;\n    background: var(--accent);\n    border-radius: 50%;\n    flex-shrink: 0;\n  }\n\n  /* ── RIGHT PANEL (form) ── */\n  .auth-form-panel {\n    padding: 48px;\n    display: flex;\n    flex-direction: column;\n    justify-content: center;\n    background: var(--surface);\n  }\n\n  .auth-tabs {\n    display: flex;\n    gap: 0;\n    background: var(--surface-2);\n    border: 1px solid var(--border);\n    border-radius: 100px;\n    padding: 4px;\n    margin-bottom: 32px;\n  }\n\n  .auth-tab {\n    flex: 1;\n    padding: 9px 16px;\n    border: none;\n    background: transparent;\n    color: var(--text-muted);\n    font-family: \'DM Sans\', sans-serif;\n    font-size: 13px;\n    font-weight: 500;\n    border-radius: 100px;\n    cursor: pointer;\n    transition: all 0.2s;\n    text-align: center;\n  }\n\n  .auth-tab.active {\n    background: var(--accent);\n    color: #000;\n    font-weight: 700;\n  }\n\n  .auth-form { display: none; }\n  .auth-form.active { display: block; animation: fadeSlide 0.25s ease; }\n\n  @keyframes fadeSlide {\n    from { opacity: 0; transform: translateX(10px); }\n    to   { opacity: 1; transform: translateX(0); }\n  }\n\n  .form-title {\n    font-family: \'Syne\', sans-serif;\n    font-weight: 700;\n    font-size: 22px;\n    color: var(--text);\n    margin-bottom: 6px;\n  }\n\n  .form-subtitle {\n    font-size: 13px;\n    color: var(--text-muted);\n    margin-bottom: 28px;\n    line-height: 1.5;\n  }\n\n  /* FIELD */\n  .field {\n    margin-bottom: 16px;\n  }\n\n  .field-row {\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 12px;\n    margin-bottom: 16px;\n  }\n\n  .field-row .field { margin-bottom: 0; }\n\n  label {\n    display: block;\n    font-size: 11px;\n    font-weight: 600;\n    text-transform: uppercase;\n    letter-spacing: 1px;\n    color: var(--text-muted);\n    margin-bottom: 6px;\n  }\n\n  .input-wrap {\n    position: relative;\n  }\n\n  .input-icon {\n    position: absolute;\n    left: 14px;\n    top: 50%;\n    transform: translateY(-50%);\n    font-size: 15px;\n    pointer-events: none;\n    opacity: 0.5;\n  }\n\n  input[type="text"],\n  input[type="email"],\n  input[type="password"],\n  input[type="tel"] {\n    width: 100%;\n    background: var(--surface-2);\n    border: 1px solid var(--border);\n    border-radius: var(--radius-sm);\n    color: var(--text);\n    font-family: \'DM Sans\', sans-serif;\n    font-size: 14px;\n    padding: 12px 14px 12px 40px;\n    outline: none;\n    transition: all 0.2s;\n    -webkit-appearance: none;\n  }\n\n  input:focus {\n    border-color: var(--accent);\n    background: var(--accent-dim);\n    box-shadow: 0 0 0 3px var(--accent-glow);\n  }\n\n  input.error {\n    border-color: var(--red);\n    background: var(--red-dim);\n  }\n\n  input::placeholder { color: var(--text-muted); opacity: 0.6; }\n\n  /* toggle password visibility */\n  .eye-btn {\n    position: absolute;\n    right: 12px;\n    top: 50%;\n    transform: translateY(-50%);\n    background: none;\n    border: none;\n    color: var(--text-muted);\n    cursor: pointer;\n    font-size: 15px;\n    padding: 4px;\n    line-height: 1;\n  }\n\n  /* ERROR MESSAGE */\n  .error-msg {\n    display: none;\n    background: var(--red-dim);\n    border: 1px solid var(--red);\n    border-radius: var(--radius-sm);\n    padding: 12px 16px;\n    font-size: 13px;\n    color: var(--red);\n    margin-bottom: 16px;\n    line-height: 1.5;\n  }\n\n  .error-msg.show { display: block; animation: shake 0.3s ease; }\n\n  @keyframes shake {\n    0%,100% { transform: translateX(0); }\n    25% { transform: translateX(-6px); }\n    75% { transform: translateX(6px); }\n  }\n\n  /* SUCCESS MESSAGE */\n  .success-msg {\n    display: none;\n    background: var(--green-dim);\n    border: 1px solid var(--green);\n    border-radius: var(--radius-sm);\n    padding: 12px 16px;\n    font-size: 13px;\n    color: var(--green);\n    margin-bottom: 16px;\n  }\n  .success-msg.show { display: block; }\n\n  /* SUBMIT BUTTON */\n  .submit-btn {\n    width: 100%;\n    padding: 14px;\n    background: var(--accent);\n    color: #000;\n    font-family: \'Syne\', sans-serif;\n    font-weight: 700;\n    font-size: 14px;\n    border: none;\n    border-radius: var(--radius-sm);\n    cursor: pointer;\n    letter-spacing: 0.5px;\n    transition: all 0.2s;\n    margin-top: 8px;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    gap: 8px;\n    position: relative;\n    overflow: hidden;\n  }\n\n  .submit-btn:hover:not(:disabled) {\n    background: #f5ff72;\n    transform: translateY(-1px);\n    box-shadow: 0 8px 24px rgba(232,255,71,0.35);\n  }\n\n  .submit-btn:disabled {\n    opacity: 0.6;\n    cursor: not-allowed;\n    transform: none;\n  }\n\n  .btn-spinner {\n    display: none;\n    width: 16px; height: 16px;\n    border: 2px solid rgba(0,0,0,0.3);\n    border-top-color: #000;\n    border-radius: 50%;\n    animation: spin 0.7s linear infinite;\n  }\n\n  @keyframes spin { to { transform: rotate(360deg); } }\n\n  .submit-btn.loading .btn-text { display: none; }\n  .submit-btn.loading .btn-spinner { display: block; }\n\n  /* DIVIDER */\n  .auth-divider {\n    display: flex;\n    align-items: center;\n    gap: 12px;\n    margin: 20px 0;\n    font-size: 11px;\n    color: var(--text-muted);\n    text-transform: uppercase;\n    letter-spacing: 1px;\n  }\n  .auth-divider::before, .auth-divider::after {\n    content: \'\'; flex: 1; height: 1px; background: var(--border);\n  }\n\n  /* JOB REF LOOKUP */\n  .job-lookup-wrap {\n    background: var(--surface-2);\n    border: 1px solid var(--border);\n    border-radius: var(--radius-sm);\n    padding: 16px;\n    margin-top: 12px;\n    display: none;\n  }\n  .job-lookup-wrap.show { display: block; animation: fadeSlide 0.2s ease; }\n  .job-lookup-label {\n    font-size: 11px;\n    font-weight: 600;\n    text-transform: uppercase;\n    letter-spacing: 1px;\n    color: var(--text-muted);\n    margin-bottom: 8px;\n  }\n  .job-result-item {\n    display: flex;\n    justify-content: space-between;\n    align-items: center;\n    padding: 10px 12px;\n    background: var(--surface);\n    border: 1px solid var(--border);\n    border-radius: 8px;\n    margin-bottom: 6px;\n    cursor: pointer;\n    transition: all 0.15s;\n    font-size: 13px;\n  }\n  .job-result-item:hover {\n    border-color: var(--accent);\n    background: var(--accent-dim);\n  }\n  .job-result-ref {\n    font-family: \'Syne\', sans-serif;\n    font-weight: 700;\n    font-size: 12px;\n    color: var(--accent);\n  }\n  .job-result-vehicle { color: var(--text-muted); font-size: 12px; }\n\n  ::-webkit-scrollbar { width: 5px; }\n  ::-webkit-scrollbar-track { background: transparent; }\n  ::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }\n\n  @media(max-width: 700px) {\n    .auth-split { grid-template-columns: 1fr; max-width: 440px; }\n    .auth-brand { display: none; }\n    .auth-form-panel { padding: 32px 24px; }\n  }'

AUTH_BODY = '<div class="auth-root">\n  <div class="auth-split">\n\n    <!-- LEFT: BRANDING -->\n    <div class="auth-brand">\n      <div class="brand-logo">\n        <div class="brand-logo-mark">&#9881;</div>\n        AutoCare Portal\n      </div>\n      <div>\n        <div class="brand-tagline">Your garage,<br><span>always in sync.</span></div>\n        <div class="brand-desc">Track your vehicle\'s service journey from check-in to payment &mdash; all in one place.</div>\n        <div class="brand-features">\n          <div class="brand-feature"><div class="brand-feature-dot"></div>Real-time service updates</div>\n          <div class="brand-feature"><div class="brand-feature-dot"></div>View &amp; approve quotations</div>\n          <div class="brand-feature"><div class="brand-feature-dot"></div>Download invoices instantly</div>\n          <div class="brand-feature"><div class="brand-feature-dot"></div>Pay via M-PESA, card or cash</div>\n          <div class="brand-feature"><div class="brand-feature-dot"></div>Full service history</div>\n        </div>\n      </div>\n      <div style="font-size:11px;color:var(--text-muted)">&#169; 2025 AutoCare Garage Ltd. &middot; Nairobi</div>\n    </div>\n\n    <!-- RIGHT: FORM -->\n    <div class="auth-form-panel">\n\n      <!-- TABS -->\n      <div class="auth-tabs">\n        <button class="auth-tab active" id="tab-login" data-action="tab-login">Sign In</button>\n        <button class="auth-tab" id="tab-signup" data-action="tab-signup">Create Account</button>\n      </div>\n\n      <!-- LOGIN FORM -->\n      <div class="auth-form active" id="form-login">\n        <div class="form-title">Welcome back</div>\n        <div class="form-subtitle">Sign in to track your vehicle service.</div>\n        <div class="error-msg" id="login-error"></div>\n        <div class="success-msg" id="login-success"></div>\n        <div class="field">\n          <label for="login-email">Email address</label>\n          <div class="input-wrap">\n            <span class="input-icon">&#9993;</span>\n            <input type="email" id="login-email" placeholder="you@example.com" autocomplete="email">\n          </div>\n        </div>\n        <div class="field">\n          <label for="login-password">Password</label>\n          <div class="input-wrap">\n            <span class="input-icon">&#128274;</span>\n            <input type="password" id="login-password" placeholder="Your password" autocomplete="current-password">\n            <button class="eye-btn" id="toggle-login-pwd" tabindex="-1">&#128065;</button>\n          </div>\n        </div>\n        <button class="submit-btn" id="login-btn">\n          <span class="btn-text">Sign In &#8594;</span>\n          <div class="btn-spinner"></div>\n        </button>\n        <div class="auth-divider">or</div>\n        <div style="text-align:center;font-size:13px;color:var(--text-muted)">\n          Don\'t have an account?\n          <span class="switch-link" id="link-to-signup" style="color:var(--accent);cursor:pointer;font-weight:600">Create one &#8594;</span>\n        </div>\n      </div>\n\n      <!-- SIGNUP FORM -->\n      <div class="auth-form" id="form-signup">\n        <div class="form-title">Create account</div>\n        <div class="form-subtitle">Join as an existing or new customer.</div>\n        <div class="error-msg" id="signup-error"></div>\n        <div class="success-msg" id="signup-success"></div>\n        <div class="field-row">\n          <div class="field">\n            <label for="signup-firstname">First Name</label>\n            <div class="input-wrap">\n              <span class="input-icon">&#128100;</span>\n              <input type="text" id="signup-firstname" placeholder="James">\n            </div>\n          </div>\n          <div class="field">\n            <label for="signup-lastname">Last Name</label>\n            <div class="input-wrap">\n              <span class="input-icon">&#128100;</span>\n              <input type="text" id="signup-lastname" placeholder="Odhiambo">\n            </div>\n          </div>\n        </div>\n        <div class="field">\n          <label for="signup-email">Email address</label>\n          <div class="input-wrap">\n            <span class="input-icon">&#9993;</span>\n            <input type="email" id="signup-email" placeholder="you@example.com" autocomplete="email">\n          </div>\n        </div>\n        <div class="field">\n          <label for="signup-phone">Phone number</label>\n          <div class="input-wrap">\n            <span class="input-icon">&#128241;</span>\n            <input type="tel" id="signup-phone" placeholder="+254 7XX XXX XXX">\n          </div>\n        </div>\n        <div class="field">\n          <label for="signup-password">Password</label>\n          <div class="input-wrap">\n            <span class="input-icon">&#128274;</span>\n            <input type="password" id="signup-password" placeholder="Min. 8 characters" autocomplete="new-password">\n            <button class="eye-btn" id="toggle-signup-pwd" tabindex="-1">&#128065;</button>\n          </div>\n        </div>\n        <div class="field">\n          <label for="signup-password2">Confirm password</label>\n          <div class="input-wrap">\n            <span class="input-icon">&#128274;</span>\n            <input type="password" id="signup-password2" placeholder="Repeat password" autocomplete="new-password">\n          </div>\n        </div>\n        <div style="display:flex;align-items:center;gap:10px;margin-bottom:4px">\n          <input type="checkbox" id="existing-customer-chk"\n            style="width:16px;height:16px;accent-color:var(--accent);cursor:pointer">\n          <label for="existing-customer-chk"\n            style="font-size:13px;text-transform:none;letter-spacing:0;color:var(--text-mid);cursor:pointer;margin:0">\n            I\'m an existing customer &mdash; link my records\n          </label>\n        </div>\n        <div class="job-lookup-wrap" id="job-lookup-wrap">\n          <div class="job-lookup-label">Enter your Job Reference</div>\n          <div class="input-wrap" style="margin-bottom:10px">\n            <span class="input-icon">&#128269;</span>\n            <input type="text" id="job-ref-input" placeholder="e.g. GRG-2025-0001">\n          </div>\n          <div id="job-lookup-results"></div>\n        </div>\n        <button class="submit-btn" id="signup-btn" style="margin-top:16px">\n          <span class="btn-text">Create Account &#8594;</span>\n          <div class="btn-spinner"></div>\n        </button>\n        <div class="auth-divider">or</div>\n        <div style="text-align:center;font-size:13px;color:var(--text-muted)">\n          Already have an account?\n          <span class="switch-link" id="link-to-login" style="color:var(--accent);cursor:pointer;font-weight:600">Sign in &#8594;</span>\n        </div>\n      </div>\n\n    </div>\n  </div>\n</div>'

AUTH_JS   = '\n(function() {\n  // ── UTILITIES ──────────────────────────────────────────\n  function $(id) { return document.getElementById(id); }\n\n  function showMsg(id, msg) {\n    var el = $(id);\n    if (!el) return;\n    el.textContent = msg;\n    el.classList.add(\'show\');\n  }\n\n  function clearMessages() {\n    [\'login-error\',\'login-success\',\'signup-error\',\'signup-success\'].forEach(function(id) {\n      var el = $(id);\n      if (el) { el.classList.remove(\'show\'); el.textContent = \'\'; }\n    });\n  }\n\n  function setLoading(btnId, on) {\n    var btn = $(btnId);\n    if (!btn) return;\n    btn.disabled = on;\n    btn.classList.toggle(\'loading\', on);\n  }\n\n  // ── TAB SWITCHING ──────────────────────────────────────\n  function switchTab(tab) {\n    [\'login\',\'signup\'].forEach(function(t) {\n      var tabEl  = $(\'tab-\'  + t);\n      var formEl = $(\'form-\' + t);\n      if (tabEl)  tabEl.classList.toggle(\'active\',  t === tab);\n      if (formEl) formEl.classList.toggle(\'active\', t === tab);\n    });\n    clearMessages();\n  }\n\n  // Tab buttons\n  var tabLogin  = $(\'tab-login\');\n  var tabSignup = $(\'tab-signup\');\n  if (tabLogin)  tabLogin.addEventListener(\'click\',  function() { switchTab(\'login\');  });\n  if (tabSignup) tabSignup.addEventListener(\'click\', function() { switchTab(\'signup\'); });\n\n  // "Create one" / "Sign in" text links\n  var linkToSignup = $(\'link-to-signup\');\n  var linkToLogin  = $(\'link-to-login\');\n  if (linkToSignup) linkToSignup.addEventListener(\'click\', function() { switchTab(\'signup\'); });\n  if (linkToLogin)  linkToLogin.addEventListener(\'click\',  function() { switchTab(\'login\');  });\n\n  // ── PASSWORD VISIBILITY TOGGLE ─────────────────────────\n  function makeEyeToggle(btnId, inputId) {\n    var btn = $(btnId);\n    var inp = $(inputId);\n    if (!btn || !inp) return;\n    btn.addEventListener(\'click\', function(e) {\n      e.preventDefault();\n      if (inp.type === \'password\') {\n        inp.type = \'text\';\n        btn.innerHTML = \'&#128584;\';\n      } else {\n        inp.type = \'password\';\n        btn.innerHTML = \'&#128065;\';\n      }\n    });\n  }\n  makeEyeToggle(\'toggle-login-pwd\',  \'login-password\');\n  makeEyeToggle(\'toggle-signup-pwd\', \'signup-password\');\n\n  // ── EXISTING CUSTOMER TOGGLE ───────────────────────────\n  var existingChk    = $(\'existing-customer-chk\');\n  var jobLookupWrap  = $(\'job-lookup-wrap\');\n  var jobRefInput    = $(\'job-ref-input\');\n  var jobResults     = $(\'job-lookup-results\');\n  var selectedJobRef = null;\n\n  if (existingChk) {\n    existingChk.addEventListener(\'change\', function() {\n      if (jobLookupWrap) jobLookupWrap.classList.toggle(\'show\', existingChk.checked);\n      if (!existingChk.checked) {\n        if (jobRefInput) jobRefInput.value = \'\';\n        if (jobResults)  jobResults.innerHTML = \'\';\n        selectedJobRef = null;\n      }\n    });\n  }\n\n  // ── JOB REFERENCE LOOKUP (debounced) ──────────────────\n  var lookupTimer = null;\n\n  function renderJobResults(jobs) {\n    if (!jobResults) return;\n    if (!jobs || jobs.length === 0) {\n      jobResults.innerHTML = \'<div style="font-size:12px;color:var(--text-muted);padding:6px 0">No jobs found for that reference.</div>\';\n      return;\n    }\n    jobResults.innerHTML = \'\';\n    jobs.forEach(function(j) {\n      var item = document.createElement(\'div\');\n      item.className = \'job-result-item\';\n      item.innerHTML =\n        \'<div>\' +\n          \'<div class="job-result-ref">\' + j.job_ref + \'</div>\' +\n          \'<div class="job-result-vehicle">\' + j.vehicle + \'</div>\' +\n        \'</div>\' +\n        \'<div style="font-size:11px;color:var(--text-muted)">\' + j.date + \'</div>\';\n      item.addEventListener(\'click\', function() {\n        selectedJobRef = j.job_ref;\n        if (jobRefInput) jobRefInput.value = j.job_ref;\n        jobResults.innerHTML =\n          \'<div style="font-size:12px;color:var(--green);padding:6px 0">&#10003; Job \' +\n          j.job_ref + \' selected &mdash; \' + j.vehicle + \'</div>\';\n      });\n      jobResults.appendChild(item);\n    });\n  }\n\n  if (jobRefInput) {\n    jobRefInput.addEventListener(\'input\', function() {\n      clearTimeout(lookupTimer);\n      selectedJobRef = null;\n      if (jobResults) jobResults.innerHTML = \'\';\n      var val = jobRefInput.value.trim();\n      if (val.length < 3) return;\n      if (jobResults) jobResults.innerHTML = \'<div style="font-size:12px;color:var(--text-muted);padding:6px 0">Searching...</div>\';\n      lookupTimer = setTimeout(function() {\n        if (typeof window._anvilJobLookup === \'function\') {\n          Promise.resolve(window._anvilJobLookup(val))\n            .then(renderJobResults)\n            .catch(function() {\n              if (jobResults) jobResults.innerHTML = \'<div style="font-size:12px;color:var(--red)">Lookup failed.</div>\';\n            });\n        }\n      }, 400);\n    });\n  }\n\n  // ── LOGIN ──────────────────────────────────────────────\n  function doLogin() {\n    clearMessages();\n    var email    = $(\'login-email\')    ? $(\'login-email\').value.trim()    : \'\';\n    var password = $(\'login-password\') ? $(\'login-password\').value         : \'\';\n    if (!email || !password) {\n      showMsg(\'login-error\', \'Please enter your email and password.\');\n      return;\n    }\n    setLoading(\'login-btn\', true);\n    if (typeof window._anvilLogin !== \'function\') {\n      showMsg(\'login-error\', \'Auth service not ready. Please wait a moment and try again.\');\n      setLoading(\'login-btn\', false);\n      return;\n    }\n    Promise.resolve(window._anvilLogin(email, password))\n      .then(function(result) {\n        setLoading(\'login-btn\', false);\n        if (result && result.success) {\n          showMsg(\'login-success\', \'&#10003; Signed in! Loading your portal...\');\n          setTimeout(function() {\n            if (typeof window._anvilLoginSuccess === \'function\') {\n              window._anvilLoginSuccess(result);\n            }\n          }, 800);\n        } else {\n          showMsg(\'login-error\', (result && result.error) || \'Invalid email or password.\');\n        }\n      })\n      .catch(function(err) {\n        setLoading(\'login-btn\', false);\n        showMsg(\'login-error\', String(err) || \'Login failed. Please try again.\');\n      });\n  }\n\n  var loginBtn = $(\'login-btn\');\n  if (loginBtn) loginBtn.addEventListener(\'click\', doLogin);\n\n  // ── SIGNUP ─────────────────────────────────────────────\n  function doSignup() {\n    clearMessages();\n    var first    = $(\'signup-firstname\') ? $(\'signup-firstname\').value.trim() : \'\';\n    var last     = $(\'signup-lastname\')  ? $(\'signup-lastname\').value.trim()  : \'\';\n    var email    = $(\'signup-email\')     ? $(\'signup-email\').value.trim()     : \'\';\n    var phone    = $(\'signup-phone\')     ? $(\'signup-phone\').value.trim()     : \'\';\n    var pwd      = $(\'signup-password\')  ? $(\'signup-password\').value          : \'\';\n    var pwd2     = $(\'signup-password2\') ? $(\'signup-password2\').value         : \'\';\n    var existing = existingChk           ? existingChk.checked                 : false;\n\n    if (!first || !last)  { showMsg(\'signup-error\', \'Please enter your full name.\');         return; }\n    if (!email)           { showMsg(\'signup-error\', \'Please enter your email address.\');     return; }\n    if (!phone)           { showMsg(\'signup-error\', \'Please enter your phone number.\');      return; }\n    if (pwd.length < 8)   { showMsg(\'signup-error\', \'Password must be at least 8 characters.\'); return; }\n    if (pwd !== pwd2)     { showMsg(\'signup-error\', \'Passwords do not match.\');              return; }\n    if (existing && !selectedJobRef) {\n      showMsg(\'signup-error\', \'Please select a job from the lookup to link your existing records.\');\n      return;\n    }\n\n    setLoading(\'signup-btn\', true);\n\n    if (typeof window._anvilSignup !== \'function\') {\n      showMsg(\'signup-error\', \'Auth service not ready. Please wait a moment and try again.\');\n      setLoading(\'signup-btn\', false);\n      return;\n    }\n\n    var payload = {\n      first_name: first,\n      last_name:  last,\n      email:      email,\n      phone:      phone,\n      password:   pwd,\n      job_ref:    selectedJobRef || null\n    };\n\n    Promise.resolve(window._anvilSignup(payload))\n      .then(function(result) {\n        setLoading(\'signup-btn\', false);\n        if (result && result.success) {\n          showMsg(\'signup-success\', \'&#10003; Account created! Signing you in...\');\n          setTimeout(function() {\n            if (typeof window._anvilLoginSuccess === \'function\') {\n              window._anvilLoginSuccess(result);\n            }\n          }, 1000);\n        } else {\n          showMsg(\'signup-error\', (result && result.error) || \'Signup failed. Please try again.\');\n        }\n      })\n      .catch(function(err) {\n        setLoading(\'signup-btn\', false);\n        showMsg(\'signup-error\', String(err) || \'Signup failed.\');\n      });\n  }\n\n  var signupBtn = $(\'signup-btn\');\n  if (signupBtn) signupBtn.addEventListener(\'click\', doSignup);\n\n  // ── ENTER KEY SUPPORT ──────────────────────────────────\n  document.addEventListener(\'keydown\', function(e) {\n    if (e.key !== \'Enter\') return;\n    var loginActive = $(\'form-login\') && $(\'form-login\').classList.contains(\'active\');\n    if (loginActive) doLogin();\n    else doSignup();\n  });\n\n  console.log(\'[AutoCare] Auth JS wired up successfully.\');\n})();\n'